87	          -- Transmitting
88	          if bclk = '1' then
89	            Buf <= '1' & Buf(Buf'left downto 1);
90	            Cnt <= Cnt + 1;
91	          end if;
92	        end if;
93	      end if;
94	    end if;
95	  end process;
96		tx  <= Buf(0);
97		ful <= Cnt(Cnt'left);
98	end;
