37	package uart is
38		type T_IO_UART_FLOWCONTROL_KIND is (
39			UART_FLOWCONTROL_NONE,
40			UART_FLOWCONTROL_XON_XOFF,
41			UART_FLOWCONTROL_RTS_CTS,
42			UART_FLOWCONTROL_RTR_CTS
43		);
44	
45		constant C_IO_UART_TYPICAL_BAUDRATES : T_BAUDVEC := (
46			 0 =>		 300 Bd,	 1 =>		 600 Bd,	 2 =>		1200 Bd,	 3 =>		1800 Bd,	 4 =>		2400 Bd,
47			 5 =>		4000 Bd,	 6 =>		4800 Bd,	 7 =>		7200 Bd,	 8 =>		9600 Bd,	 9 =>	 14400 Bd,
48			10 =>	 16000 Bd,	11 =>	 19200 Bd,	12 =>	 28800 Bd,	13 =>	 38400 Bd,	14 =>	 51200 Bd,
49			15 =>	 56000 Bd,	16 =>	 57600 Bd,	17 =>	 64000 Bd,	18 =>	 76800 Bd,	19 =>	115200 Bd,
50			20 =>	128000 Bd,	21 =>	153600 Bd,	22 =>	230400 Bd,	23 =>	250000 Bd,	24 =>	256000 Bd,
51			25 =>	460800 Bd,	26 =>	500000 Bd,	27 =>	576000 Bd,	28 =>	921600 Bd
52		);
53	
54		function io_UART_IsTypicalBaudRate(br : BAUD) return boolean;
55	
56	  -- Bit Clock Generator: 8 Ticks per Bit
57	  component uart_bclk
58	    generic (
59	      CLK_FREQ : positive;
60	      BAUDRATE : positive
61	    );
62	    port (
63	      clk     : in  std_logic;
64	      rst     : in  std_logic;
65	      bclk    : out std_logic;
66	      bclk_x8 : out std_logic
67	    );
68	  end component;
69	
70	  -- Receiver
71	  component uart_rx is
72	    generic (
73	      SYNC_DEPTH : natural := 2  -- use zero for already clock-synchronous rx
74	    );
75	    port (
76	      -- Global Control
77	      clk : in std_logic;
78	      rst : in std_logic;
79	
80	      -- Bit Clock and RX Line
81	      bclk_x8 : in std_logic;  	-- bit clock, eight strobes per bit length
82	      rx      : in std_logic;
83	
84	      -- Byte Stream Output
85	      do  : out std_logic_vector(7 downto 0);
86	      stb : out std_logic
87	    );
88	  end component;
89	
90	  -- Transmitter
91		component uart_tx is
92			port (
93				-- Global Control
94				clk : in std_logic;
95				rst : in std_logic;
96	
97				-- Bit Clock and TX Line
98				bclk : in  std_logic;  -- bit clock, one strobe each bit length
99				tx   : out std_logic;
100	
101				-- Byte Stream Input
102				di  : in  std_logic_vector(7 downto 0);
103				put : in  std_logic;
104				ful : out std_logic
105			);
106		end component;
107	
108	  -- Wrappers
109	  -- ===========================================================================
110	  -- UART with FIFOs and optional flow control
111	  component uart_fifo is
112	    generic (
113	      -- Communication Parameters
114	      CLOCK_FREQ  : FREQ;
115	      BAUDRATE    : BAUD;
116	
117				-- Buffer Dimensioning
118	      TX_MIN_DEPTH   : positive := 16;
119	      TX_ESTATE_BITS : natural  :=  0;
120	      RX_MIN_DEPTH   : positive := 16;
121	      RX_FSTATE_BITS : natural  :=  0;
122	
123	      -- Flow Control
124	      FLOWCONTROL       : T_IO_UART_FLOWCONTROL_KIND   := UART_FLOWCONTROL_NONE;
125	      SWFC_XON_CHAR     : std_logic_vector(7 downto 0) := x"11";  -- ^Q
126	      SWFC_XON_TRIGGER  : real                         := 0.0625;
127	      SWFC_XOFF_CHAR    : std_logic_vector(7 downto 0) := x"13";  -- ^S
128	      SWFC_XOFF_TRIGGER : real                         := 0.75
129	    );
130	    port (
131	      Clock : in std_logic;
132	      Reset : in std_logic;
133	
134	      -- FIFO interface
135	      TX_put        : in  std_logic;
136	      TX_Data       : in  std_logic_vector(7 downto 0);
137	      TX_Full       : out std_logic;
138	      TX_EmptyState : out std_logic_vector(TX_ESTATE_BITS - 1 downto 0);
139	
140	      RX_Valid     : out std_logic;
141	      RX_Data      : out std_logic_vector(7 downto 0);
142	      RX_got       : in  std_logic;
143	      RX_FullState : out std_logic_vector(RX_FSTATE_BITS - 1 downto 0);
144	      RX_Overflow  : out std_logic;
145	
146	      -- External Pins
147	      UART_RX : in  std_logic;
148	      UART_TX : out std_logic
149	    );
150		end component;
151	
152		-- USB-UART
153		component ft245_uart is
154			generic (
155	      CLK_FREQ : positive
156			);
157			port (
158	      -- common signals
159	      clk         : in  std_logic;
160	      reset       : in  std_logic;
161	
162	      -- send data
163	      snd_ready   : out std_logic;
164	      snd_strobe  : in  std_logic;
165	      snd_data    : in  std_logic_vector(7 downto 0);
166	
167	      -- receive data
168	      rec_strobe  : out std_logic;
169	      rec_data    : out std_logic_vector(7 downto 0);
170	
171	      -- connection to ft245
172	      ft245_data  : inout std_logic_vector (7 downto 0);
173	      ft245_rdn   : out std_logic;
174	      ft245_wrn   : out std_logic;
175	      ft245_rxfn  : in std_logic;
176	      ft245_txen  : in std_logic;
177	      ft245_pwrenn : in std_logic
178			);
179		end component;
180	
181	end package;
182	
183	
184	package body uart is
185		function io_UART_IsTypicalBaudRate(br : BAUD) return boolean is
186		begin
187			for i in C_IO_UART_TYPICAL_BAUDRATES'range loop
188				next when (br /= C_IO_UART_TYPICAL_BAUDRATES(i));
189				return TRUE;
190			end loop;
191			return FALSE;
192		end function;
193	end package body;
