54	    CLOCK_FREQ 							: FREQ;
55	    BOUNCE_TIME							: time;
56	    BITS                    : positive := 1;
57			INIT										: std_logic_vector		:= x"00000000";	-- initial state of Output
58	    ADD_INPUT_SYNCHRONIZERS : boolean  := true;
59	    COMMON_LOCK             : boolean  := false
60	  );
61	  port (
62	    Clock		: in	std_logic;
63			Reset		: in	std_logic							:= '0';
64	    Input		: in	std_logic_vector(BITS-1 downto 0);
65	    Output	: out	std_logic_vector(BITS-1 downto 0) := resize(descend(INIT), BITS)
66	  );
67	end entity;
