70	architecture rtl of io_Debounce is
71		-- Number of required locking cycles
72		constant LOCK_COUNT_X : integer := TimingToCycles(BOUNCE_TIME, CLOCK_FREQ) - 1;
73	
74		-- Input Refinements
75	  signal sync		: std_logic_vector(Input'range);										-- Synchronized
76	  signal prev		: std_logic_vector(Input'range) := (others => '0');	-- Delayed
77		signal active	: std_logic_vector(Input'range);										-- Allow Output Updates
78	
79	begin
80	  -----------------------------------------------------------------------------
81	  -- Input Synchronization
82	  genNoSync: if not ADD_INPUT_SYNCHRONIZERS generate
83	    sync <= Input;
84	  end generate;
85	  genSync: if ADD_INPUT_SYNCHRONIZERS generate
86	    sync_i : entity PoC.sync_Bits
87	      generic map (
88	        BITS => BITS,
89					INIT => INIT
90	      )
91	      port map (
92	        Clock  => Clock,  	-- Clock to be synchronized to
93	        Input  => Input,  	-- Data to be synchronized
94	        Output => sync  		-- synchronised data
95	      );
96	  end generate;
97	
98		-----------------------------------------------------------------------------
99		-- Bounce Filter
100		process(Clock)
101		begin
102			if rising_edge(Clock) then
103				prev <= sync;
104				if (Reset = '1') then
105					Output <= sync;
106				else
107					for i in Output'range loop
108						if active(i) = '1' then
109							Output(i) <= sync(i);
110						end if;
111					end loop;
112				end if;
113			end if;
114		end process;
115	
116		genNoLock: if LOCK_COUNT_X <= 0 generate
117			active <= (others => '1');
118		end generate genNoLock;
119		genLock: if LOCK_COUNT_X > 0 generate
120			constant LOCKS	: positive := ite(COMMON_LOCK, 1, BITS);
121	
122			signal toggle		: std_logic_vector(LOCKS-1 downto 0);
123			signal locked		: std_logic_vector(LOCKS-1 downto 0);
124		begin
125	
126	    genOneLock: if COMMON_LOCK generate
127	      toggle(0) <= '1' when prev /= sync else '0';
128	      active    <= (others => not locked(0));
129	    end generate genOneLock;
130	    genManyLocks: if not COMMON_LOCK generate
131	      toggle <= prev xor sync;
132	      active <= not locked;
133	    end generate genManyLocks;
134	
135			genLocks: for i in 0 to LOCKS-1 generate
136				signal Lock : signed(log2ceil(LOCK_COUNT_X+1) downto 0) := (others => '0');
